-- Poland – Student Visa (National D + Residence for Studies) — 30 FAQs
UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee student visa approval?","a":"No. Embassy decides based on admission, funds, and credibility. Never promise approval."},{"q":"What is proof of funds for Poland?","a":"Typically €800/month (verify UdSC amount) months (€9,600+/year) living funds or equivalent. Verify current amount on www.gov.pl before quoting."},{"q":"Proof of funds amount for 2026?","a":"Typically €800/month (verify UdSC amount) (€9,600+/year). Verify current amount on www.gov.pl before quoting."},{"q":"Can spouse accompany?","a":"Dependants may apply separately; prove additional funds and accommodation. Assess case-by-case."},{"q":"English-taught programs need Polish?","a":"Depends on program—follow admission and embassy requirements."},{"q":"How long to convert to residence permit?","a":"Apply at Migration Department (www.gov.pl) soon after arrival and university registration."},{"q":"Can I work on student visa?","a":"Limited working hours permitted—verify current rules for students in Poland."},{"q":"What after graduation?","a":"Discuss Graduate job-search temporary residence permit (verify on www.gov.pl) separately."},{"q":"What is Description for this service?","a":"National visa (Type D) for study at a recognised Polish university. After entry, apply for temporary residence permit at Migration Department (www.gov.pl)."},{"q":"What is Eligible applicants for this service?","a":"University admission letter · Proof of funds (€800/month (verify UdSC amount)) · Health insurance · Motivation letter · Valid passport · Language proficiency as required"},{"q":"What is Proof of funds for this service?","a":"€800/month (verify UdSC amount) months (€9,600+/year) typically required unless scholarship or sponsor alternative applies."},{"q":"Important note on Proof of funds?","a":"€800/month (verify UdSC amount) months (€9,600+/year) typically required unless scholarship or sponsor alternative applies."},{"q":"What is Key authority for this service?","a":"Polish Embassy/Consulate in India · VFS Global Poland · Migration Department (www.gov.pl) after arrival"},{"q":"What is After approval for this service?","a":"Enter Poland; register address; apply for temporary residence permit at Migration Department (www.gov.pl) within visa validity."},{"q":"Is Admission from recognised Polish institution required?","a":"Admission from recognised Polish institution is typically required."},{"q":"Is Proof of funds (€800/month (verify UdSC amount)) required?","a":"Apply early—processing takes weeks"},{"q":"Is Proof of funds or financial proof required?","a":"€9,600+/year or equivalent with 3–6 month bank history"},{"q":"Is Health insurance (travel + statutory) required?","a":"Assess whether Health insurance (travel + statutory) is satisfied for this case."},{"q":"Is Motivation letter and CV required?","a":"Motivation letter and CV is typically required."},{"q":"Is Language proficiency (as required) required?","a":"Polish or English per program"},{"q":"Is Valid passport required?","a":"Valid passport is typically required."},{"q":"What is the Processing time?","a":"6–12w — After complete file complete"},{"q":"What is the Government fee?","a":"€75 — + proof of funds required living funds"},{"q":"What is the Our approval rate?","a":"88% — ~74% benchmark"},{"q":"What is the Required docs?","a":"15 — + proof of funds €9,600+"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & third-party"},{"q":"What if the client has Proof of funds insufficient?","a":"Open blocked account or show €9,600+ equivalent with 3–6 month bank history before embassy slot"},{"q":"Why is Proof of funds insufficient a problem?","a":"Proof of funds below €800/month (verify UdSC amount) or inconsistent bank history."},{"q":"What if the client has Insufficient proof of funds?","a":"Open proof of funds at approved bank for full required amount"},{"q":"Why is Insufficient proof of funds a problem?","a":"Amount below required monthly sum or not from recognised provider."}]'::jsonb
), updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-0000000000dc'::uuid;

-- Poland – Schengen Visitor Visa (Type C) — 30 FAQs
UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee Schengen approval?","a":"No. Consulate decides each application individually."},{"q":"Which embassy to apply?","a":"Country of main destination or first entry if equal stays—follow Schengen rules."},{"q":"How much travel insurance?","a":"Minimum €30,000 medical coverage valid across Schengen for entire trip."},{"q":"Can I visit multiple Schengen countries?","a":"Yes on single visa if main destination rule followed; respect 90/180 limit."},{"q":"How long processing?","a":"Typically 2–4 weeks; apply well before travel date."},{"q":"Does prior UK/US refusal affect Schengen?","a":"Must disclose; consulate considers overall immigration history."},{"q":"Can visitor work?","a":"No. Employment not permitted on Schengen short-stay visa."},{"q":"Reapply after refusal?","a":"Yes when circumstances improve; address prior refusal grounds."},{"q":"What is Description for this service?","a":"Schengen Type C short-stay visa for tourism, family visits, or business trips to Poland up to 90 days per 180-day period."},{"q":"What is Eligible applicants for this service?","a":"Temporary visit purpose · Travel insurance €30,000+ · Funds for trip · Strong ties to India · Clean Schengen history"},{"q":"What is Main destination rule for this service?","a":"Apply at embassy of main Schengen destination. If Poland is primary stay, apply via Polish mission."},{"q":"Important note on Main destination rule?","a":"Apply at embassy of main Schengen destination. If Poland is primary stay, apply via Polish mission."},{"q":"What is Key authority for this service?","a":"Polish Embassy/Consulate · VFS Global (appointment partner in India)"},{"q":"What is After approval for this service?","a":"Respect visa validity and 90/180 rule. Overstay affects future Schengen applications."},{"q":"Is Valid passport (3+ months beyond stay) required?","a":"Valid passport (3+ months beyond stay) is typically required."},{"q":"Is Travel medical insurance €30,000+ required?","a":"Valid for entire Schengen stay"},{"q":"Is Proof of accommodation and itinerary required?","a":"Proof of accommodation and itinerary is typically required."},{"q":"Is Proof of funds required?","a":"Proof of funds is typically required."},{"q":"Is Strong ties to India required?","a":"Strong ties to India is typically required."},{"q":"Is Cover letter explaining purpose required?","a":"Cover letter explaining purpose is typically required."},{"q":"Is Biometrics (if not in VIS) required?","a":"Assess whether Biometrics (if not in VIS) is satisfied for this case."},{"q":"What is the Processing time?","a":"2–4w — Schengen standard"},{"q":"What is the Government fee?","a":"€90 — Adult Schengen visa"},{"q":"What is the Our approval rate?","a":"76% — ~64% benchmark"},{"q":"What is the Required docs?","a":"10 — + travel insurance"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & insurance"},{"q":"What if the client has Weak ties to India?","a":"Employment letter, business proof, property, family obligations"},{"q":"Why is Weak ties to India a problem?","a":"Unemployed, no assets, vague return plan."},{"q":"What if the client has Insufficient travel insurance?","a":"Purchase Schengen-compliant insurance for full trip dates"},{"q":"Why is Insufficient travel insurance a problem?","a":"Coverage below €30,000 or wrong dates."}]'::jsonb
), updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-0000000000dd'::uuid;

-- Poland – Family Reunification (Spouse / Join Family) — 30 FAQs
UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee spouse visa approval?","a":"No. Embassy assesses marriage genuineness, sponsor status, and requirements. Never promise approval."},{"q":"Is A1 Polish mandatory for all spouses?","a":"Generally yes for spouses of non-EU residents; exemptions exist—verify on embassy website for specific case."},{"q":"How long sponsor must be in Poland?","a":"Depends on sponsor status—Poland citizen or EU residents differ from permit holders. Verify current AufenthG requirements."},{"q":"Can unmarried partners apply?","a":"Family reunion typically requires marriage; registered partnership rules vary—assess separately."},{"q":"What documents from sponsor?","a":"Passport/ID, registration, lease, employment, salary, marriage cert from Standesamt if married in Poland."},{"q":"Processing time?","a":"Typically 8–16 weeks after complete submission—varies by embassy workload."},{"q":"Can spouse work after arrival?","a":"Work authorisation depends on residence permit granted—verify at Ausländerbehörde."},{"q":"Prior Schengen refusal impact?","a":"Must disclose; may affect assessment."},{"q":"What is Description for this service?","a":"National visa for spouse reunion with Poland citizen or EU resident or foreign national holding qualifying residence permit in Poland. Leads to residence permit after entry."},{"q":"What is Eligible applicants for this service?","a":"Valid marriage · Sponsor with adequate housing and income · Basic Polish A1 (generally) · Genuine relationship · Health insurance"},{"q":"What is Language requirement for this service?","a":"Spouses generally need Polish A1 certificate unless exempt (e.g., certain qualifications or EU nationals). Verify exemptions."},{"q":"Important note on Language requirement?","a":"Spouses generally need Polish A1 certificate unless exempt (e.g., certain qualifications or EU nationals). Verify exemptions."},{"q":"What is Key authority for this service?","a":"Poland Embassy in India · Ausländerbehörde in Poland after arrival"},{"q":"What is After approval for this service?","a":"Enter Poland; register address; obtain residence permit at local Ausländerbehörde."},{"q":"Is Legally valid marriage recognised in Poland required?","a":"Legally valid marriage recognised in Poland is typically required."},{"q":"Is Sponsor is Poland citizen or EU resident or qualifying resident required?","a":"Verify residence permit type"},{"q":"Is Adequate housing in Poland required?","a":"Sponsor lease/ownership proof"},{"q":"Is Sponsor income/solvency required?","a":"Per Polish requirements"},{"q":"Is Polish A1 certificate (if required) required?","a":"Goethe/ÖSD/TELC A1"},{"q":"Is Genuine relationship evidence required?","a":"Genuine relationship evidence is typically required."},{"q":"Is Health insurance arrangement required?","a":"Assess whether Health insurance arrangement is satisfied for this case."},{"q":"What is the Processing time?","a":"8–16w — After complete file"},{"q":"What is the Government fee?","a":"€75 — National visa approx"},{"q":"What is the Our approval rate?","a":"87% — ~76% benchmark"},{"q":"What is the Required docs?","a":"18 — + relationship & sponsor"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & language test"},{"q":"What if the client has Sponsor income/housing insufficient?","a":"Collect sponsor employment contract, salary slips, lease with square metres"},{"q":"Why is Sponsor income/housing insufficient a problem?","a":"Sponsor cannot prove adequate apartment size or income."},{"q":"What if the client has Missing A1 Polish certificate?","a":"Complete Goethe A1 or verify exemption applies"},{"q":"Why is Missing A1 Polish certificate a problem?","a":"Spouse applied without required basic Polish."}]'::jsonb
), updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-0000000000de'::uuid;

-- Poland – EU Blue Card / Skilled Worker Residence — 30 FAQs
UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee Opportunity Card approval?","a":"No. Embassy assesses points and documentation. Never promise approval."},{"q":"How to calculate points?","a":"Use official criteria on www.gov.pl—qualification, experience, language, age, prior Poland stay."},{"q":"Need job offer?","a":"No—that is the purpose. Search for job after arrival. Blocked account required instead."},{"q":"Can work on Opportunity Card?","a":"Limited—part-time work while searching allowed per current rules. Verify limits."},{"q":"Difference from job seeker visa?","a":"Opportunity Card replaces old job seeker for points-based pathway—verify current rules."},{"q":"Blocked account amount?","a":"Verify current amount on embassy website—similar to student blocked account."},{"q":"After finding job?","a":"Apply for work residence permit at Ausländerbehörde."},{"q":"Age limit?","a":"No strict limit but fewer age points above 35."},{"q":"What is Description for this service?","a":"Residence permit for qualified professionals to search for employment in Poland for up to one year without prior job offer. Points-based eligibility under Section 20a AufenthG."},{"q":"What is Eligible applicants for this service?","a":"Minimum 6 points · Recognised qualification or IT experience · Polish A1 or English B2 · Blocked account or employment contract · Age typically under 35 for max age points"},{"q":"What is Points system for this service?","a":"Points for qualification recognition, work experience, language, age, and previous Poland stay. Minimum 6 points required."},{"q":"Important note on Points system?","a":"Points for qualification recognition, work experience, language, age, and previous Poland stay. Minimum 6 points required."},{"q":"What is Key authority for this service?","a":"Poland Embassy in India · Local Ausländerbehörde after arrival"},{"q":"What is After approval for this service?","a":"Enter Poland; search for qualified employment; convert to work residence permit when job secured."},{"q":"Is Minimum 6 points achieved required?","a":"Calculate using official criteria"},{"q":"Is Recognised degree or IT experience pathway required?","a":"Recognised degree or IT experience pathway is typically required."},{"q":"Is Polish A1 or English B2 required?","a":"Polish A1 or English B2 is typically required."},{"q":"Is Blocked account or job offer required?","a":"Financial proof required"},{"q":"Is Qualification recognition (if claiming points) required?","a":"Anabin or partial recognition"},{"q":"Is Valid passport required?","a":"Valid passport is typically required."},{"q":"Is Health insurance required?","a":"Assess whether Health insurance is satisfied for this case."},{"q":"What is the Processing time?","a":"8–12w — Embassy processing"},{"q":"What is the Government fee?","a":"€75 — National visa approx"},{"q":"What is the Our approval rate?","a":"82% — ~70% benchmark"},{"q":"What is the Required docs?","a":"14 — + points evidence"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & blocked account"},{"q":"What if the client has Below 6 points?","a":"Calculate points honestly; improve language or get recognition"},{"q":"Why is Below 6 points a problem?","a":"Application lodged without meeting minimum points."},{"q":"What if the client has Qualification not recognised?","a":"Check Anabin database; apply for recognition if needed"},{"q":"Why is Qualification not recognised a problem?","a":"Degree not equivalent to Polish qualification for points."}]'::jsonb
), updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-0000000000df'::uuid;

