 qualification (Anabin/ZAB) required?","a":"Verify before apply"},{"q":"Is Blocked account or financial proof required?","a":"Assess whether Blocked account or financial proof is satisfied for this case."},{"q":"Is Health insurance for stay required?","a":"Assess whether Health insurance for stay is satisfied for this case."},{"q":"Is Detailed CV and cover letter required?","a":"Detailed CV and cover letter is typically required."},{"q":"Is Job search plan required?","a":"Job search plan is typically required."},{"q":"Is Valid passport required?","a":"Valid passport is typically required."},{"q":"Is Accommodation plan in Hungary required?","a":"Accommodation plan in Hungary is typically required."},{"q":"What is the Processing time?","a":"8–12w — Embassy processing"},{"q":"What is the Government fee?","a":"€75 — National visa approx"},{"q":"What is the Our approval rate?","a":"79% — ~68% benchmark"},{"q":"What is the Required docs?","a":"13 — + recognition & funds"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & blocked account"},{"q":"What if the client has Degree not recognised?","a":"Apply for recognition; consider Opportunity Card if eligible"},{"q":"Why is Degree not recognised a problem?","a":"Qualification not equivalent on Anabin/ZAB."},{"q":"What if the client has Insufficient blocked account?","a":"Open blocked account for full required period"},{"q":"Why is Insufficient blocked account a problem?","a":"Funds below required amount."}]'::jsonb
