ntire Schengen stay"},{"q":"Is Proof of accommodation and itinerary required?","a":"Proof of accommodation and itinerary is typically required."},{"q":"Is Proof of funds required?","a":"Proof of funds is typically required."},{"q":"Is Strong ties to India required?","a":"Strong ties to India is typically required."},{"q":"Is Cover letter explaining purpose required?","a":"Cover letter explaining purpose is typically required."},{"q":"Is Biometrics (if not in VIS) required?","a":"Assess whether Biometrics (if not in VIS) is satisfied for this case."},{"q":"What is the Processing time?","a":"2–4w — Schengen standard"},{"q":"What is the Government fee?","a":"€90 — Adult Schengen visa"},{"q":"What is the Our approval rate?","a":"76% — ~64% benchmark"},{"q":"What is the Required docs?","a":"10 — + travel insurance"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & insurance"},{"q":"What if the client has Weak ties to India?","a":"Employment letter, business proof, property, family obligations"},{"q":"Why is Weak ties to India a problem?","a":"Unemployed, no assets, vague return plan."},{"q":"What if the client has Insufficient travel insurance?","a":"Purchase Schengen-compliant insurance for full trip dates"},{"q":"Why is Insufficient travel insurance a problem?","a":"Coverage below €30,000 or wrong dates."}]'::jsonb
